# Private functions
  -- Coordinator
  @fn tick()  @ 67-72
      @contract  tick() runs once per frame before the page draws; no selection bus here  @ 66
  @fn drawSwitcher()  @ 74-96
  @fn dispatch(state)  @ 102-109
  -- External commands (REAPER-keymap bridge)
  @fn pollExternalCommands()  @ 117-124
  @fn anyFxFloating()  @ 128-140
      -- Any floating FX window open across master + tracks. The poll in frame() reads
      -- its open→closed edge (X button or F11) to reclaim OS focus from REAPER.
  @fn frame()  @ 142-284

# Public API (coord:*)
  @api coord:register(name, moduleName, extra)  @ 292-297
  @api coord:setActive(name)  @ 301-314
      @contract  setActive(name) no-ops if name==active; else unbind outgoing, swap scope, bind incoming  @ 299
      @contract  tracker's no-arg bind resolves its stored selection; renderBody keeps it current  @ 300
  @api coord:returnToArrange()  @ 317-320
      @contract  tracker back to arrange; no reveal (cursor never left). No-op if arrange unregistered.  @ 316
  @api coord:getFacade(name)  @ 323
      @contract  resolve a published page facade by name; the contents are owned by the publishing page  @ 322
  @api coord:previousPage()  @ 326
      @contract  the page active immediately before the current one; closeEditor returns here  @ 325
  @api coord:togglePage()  @ 330-338
      -- Cycle tracker → arrange → sample → wiring → tracker. Unregistered pages
      -- are skipped; with ≥1 track every page activates.
  @api coord:reloadAfterExternalMutation()  @ 342-347
      @contract  invoke after firing a REAPER action that mutates the bound take from inside a frame (Ctrl-Z, Ctrl-Shift-Z). The watcher's end-of-frame baseline would otherwise absorb the mutation; this reloads now so tm/vm stay coherent with the take.  @ 340
      @invariant  mirror resync precedes reload — see docs/coordinator.md § Undo mid-frame  @ 341
  @api coord:onExternalCommand(extKey, command)  @ 350-352
      @contract  registers an ExtState key→command bridge polled each frame to fire Continuum commands  @ 349
  @api coord:quit()  @ 354
  @api coord:run(handler)  @ 356
      @contract  handler wraps every deferred frame; without it, post-frame-1 errors raise raw dialogs  @ 355

